/* === app/js/lib/state.js === */
/* ═══════════════════════════════════════════════════════════════════
   NICE — State Store
   Simple pub/sub reactive state for the app.
═══════════════════════════════════════════════════════════════════ */

/**
 * @typedef {Object} StateStore
 * @property {function(string): *} get — Retrieve a value by key
 * @property {function(string, *): void} set — Set a value and notify subscribers synchronously
 * @property {function(string, *): void} setBatched — Set a value and batch notifications per animation frame
 * @property {function(string, function(*): void): void} on — Subscribe to changes for a key; fires immediately if data exists
 * @property {function(string, function(*): void): void} off — Unsubscribe a listener from a key
 */

const State = (() => {
  const _data = {};
  const _subs = {};
  let _pendingFlush = null;
  const _pendingKeys = new Set();

  /* Scoped subscriptions — auto-cleaned when destroyScoped() is called */
  let _scopedSubs = [];

  function get(key) { return _data[key]; }

  function set(key, val) {
    _data[key] = val;
    (_subs[key] || []).forEach(fn => fn(val));
  }

  /* Batch multiple rapid sets and fire listeners once per frame */
  function setBatched(key, val) {
    _data[key] = val;
    _pendingKeys.add(key);
    if (!_pendingFlush) {
      _pendingFlush = requestAnimationFrame(() => {
        _pendingKeys.forEach(k => {
          (_subs[k] || []).forEach(fn => fn(_data[k]));
        });
        _pendingKeys.clear();
        _pendingFlush = null;
      });
    }
  }

  function on(key, fn) {
    if (!_subs[key]) _subs[key] = [];
    _subs[key].push(fn);
    // Fire immediately if data exists
    if (_data[key] !== undefined) fn(_data[key]);
  }

  function off(key, fn) {
    if (!_subs[key]) return;
    _subs[key] = _subs[key].filter(f => f !== fn);
  }

  /**
   * Subscribe with automatic cleanup on view teardown.
   * Views should use this instead of on() for subscriptions that should
   * die when the view navigates away.
   * Router calls State.destroyScoped() before rendering a new view.
   */
  function onScoped(key, fn) {
    on(key, fn);
    _scopedSubs.push({ key, fn });
  }

  /** Unsubscribe all scoped listeners — called by Router on view teardown */
  function destroyScoped() {
    _scopedSubs.forEach(({ key, fn }) => off(key, fn));
    _scopedSubs = [];
  }

  /** State key registry — prevents magic strings and enables grep */
  const KEYS = {
    user: 'user',
    agents: 'agents',
    missions: 'missions',
    spaceships: 'spaceships',
    enabledModels: 'enabled_models',
    notifications: 'notifications',
    blueprints: 'blueprints',
    activeSkin: 'active_skin',
    mcpConnections: 'mcp_connections',
    tokenBalance: 'token_balance',
  };

  return { get, set, setBatched, on, off, onScoped, destroyScoped, KEYS };
})();


/* === app/js/lib/utils.js === */
/* ═══════════════════════════════════════════════════════════════════
   NICE — Utils
   Shared utility functions: HTML escaping, time formatting.
═══════════════════════════════════════════════════════════════════ */

const Utils = (() => {
  function esc(s) {
    if (s == null) return '';
    const d = document.createElement('div');
    d.textContent = String(s);
    return d.innerHTML;
  }

  function timeAgo(ts) {
    if (!ts) return '';
    const diff = Date.now() - new Date(ts).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'just now';
    if (mins < 60) return mins + 'm ago';
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return hrs + 'h ago';
    return Math.floor(hrs / 24) + 'd ago';
  }

  /** Render an SVG icon from the sprite. Usage: Utils.icon('lock') or Utils.icon('lock', 'icon-lg') */
  function icon(name, cls) {
    return `<svg class="icon ${cls || 'icon-sm'}" fill="none" stroke="currentColor" stroke-width="1.5"><use href="#icon-${name}"/></svg>`;
  }

  /** Format a date for display — consistent across all views */
  function formatDate(ts) {
    if (!ts) return '';
    return new Date(ts).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' });
  }

  function formatDateTime(ts) {
    if (!ts) return '';
    const d = new Date(ts);
    return d.toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' }) + ' ' +
      d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
  }

  /** Central localStorage key registry — prevents typos and enables grep */
  const KEYS = {
    theme: 'ns-theme',
    darkTheme: 'ns-dark-theme',
    font: 'ns-font',
    enabledModels: 'nice-enabled-models',
    xp: 'nice-xp',
    achievements: 'nice-achievements',
    auditLog: 'nice-audit-log',
    workflows: 'nice-workflows',
    mcpConnections: 'nice-mcp-connections',
    budget: 'nice-budget',
    bpActivated: 'nice-bp-activated',
    bpActivatedShips: 'nice-bp-activated-ships',
    shipState: 'nice-ship-state',
    agentStats: 'nice-agent-stats',
    favorites: 'nice-favorites',
    aiMessages: 'nice-ai-messages',
    customAgents: 'nice-custom-agents',
    customShips: 'nice-custom-ships',
    contentQueue: 'nice-content-queue',
    onboarded: 'nice-onboarded',
    plan: 'nice-plan',
    settings: 'nice-settings',
    streak: 'nice-streak',
    lastActive: 'nice-last-active',
    hudDockThemes: 'nice-hud-dock-themes',
    guiSettings: 'nice-gui-settings',
    customThemes: 'nice-custom-themes',
    missionsFolder: 'nice-missions-folder',
    modelIntel: 'nice-model-intel',
    skinInventory: 'nice-skin-inventory',
    shipBehaviors: 'nice-ship-behaviors',
    ideProjects: 'nice-ide-projects',
    ideLastProject: 'nice-ide-last-project',
    ideLayout: 'nice-ide-layout',
    missionSchedules: 'nice-mission-schedules',
    agentMemories: 'nice-agent-memories',
    quickNotes: 'nice-quick-notes',
    bpCustomLabels: 'nice-bp-custom-labels',
    bpView: 'nice-bp-view',
    bpRatings: 'nice-bp-ratings',
    agentTemplates: 'nice-agent-templates',
    agentsView: 'nice-agents-view',
    shipsView: 'nice-ships-view',
    tokens: 'nice-tokens',
    avatarUrl: 'nice-avatar-url',
    tts: 'nice-tts',
    ttsVoice: 'nice-tts-voice',
    callsign: 'nice-callsign',
    highContrast: 'nice-high-contrast',
    sidebarOrder: 'nice-sidebar-order',
  };

  return { esc, timeAgo, formatDate, formatDateTime, icon, KEYS };
})();


