    const shipSeed = (typeof BlueprintsView !== 'undefined' && BlueprintsView.SPACESHIP_SEED) ? BlueprintsView.SPACESHIP_SEED : [];
    // Show rarity/classification for experienced users (Commander+ = 100000 XP)
